const items = $input.first().json?.data || [];

const alerts = items.map(item => {
  const fields = item.fields || {};
  const country = fields.primary_country?.name || 
    (fields.country && fields.country[0]?.name) || null;

  // ReliefWeb doesn't have severity, so we use 'orange' for conflict
  const bodySnippet = (fields['body-html'] || '').replace(/<[^>]*>/g, '').substring(0, 300);

  return {
    json: {
      title: fields.title || 'ReliefWeb Report',
      summary: bodySnippet + '...',
      source: 'ReliefWeb',
      source_url: fields.url || `https://reliefweb.int/node/${item.id}`,
      image_url: null,
      severity: 'orange',
      event_type: 'war',
      latitude: null,
      longitude: null,
      country: country,
      source_id: `reliefweb-${item.id}`
    }
  };
});

return alerts.length > 0 ? alerts : [{ json: { _skip: true } }];
